  {
    icon: ShieldCheck,
    title: 'SG-SST',
    description: 'Gestión de seguridad y salud en el trabajo. Cumple con la normatividad colombiana.',
    price: 'Seguridad y salud laboral',
    color: '#F59E0B',
  },
