          <motion.p
            className="section-subtitle max-w-xl mx-auto"
            initial={{ opacity: 0, y: 15 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ delay: 0.2 }}
          >
            Soluciones de documentos electrónicos integradas y avaladas por la DIAN para empresas de todos los tamaños.
          </motion.p>
        </div>

        {/* Cards */}
        <motion.div
          className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6"
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, margin: '-60px' }}
        >
          {services.map((service) => {
            const Icon = service.icon
            return (
              <motion.div
                key={service.title}
                variants={cardVariants}
                className="card group cursor-pointer"
              >
                <div
                  className="w-12 h-12 rounded-xl flex items-center justify-center mb-4 transition-transform duration-300 group-hover:scale-110"
                  style={{ backgroundColor: `${service.color}15`, color: service.color }}
                >
                  <Icon size={24} />
                </div>
                <h3 className="text-lg font-semibold mb-2" style={{ color: 'var(--navy)' }}>
                  {service.title}
                </h3>
                <p className="text-sm leading-relaxed mb-4" style={{ color: 'var(--gray)' }}>
                  {service.description}
                </p>
                <p className="text-xs font-semibold mb-4" style={{ color: service.color }}>
                  {service.price}
                </p>
                <a
                  href="#planes"
                  className="inline-flex items-center gap-1.5 text-sm font-semibold transition-all duration-200 group-hover:gap-2.5"
                  style={{ color: 'var(--navy)' }}
                >
                  Conocer más <ArrowRight size={14} />
                </a>
              </motion.div>
            )
          })}
        </motion.div>
      </div>
    </section>
  )
}

'use client'

import { useState } from 'react'
import { Check, X, ShoppingCart, Loader2 } from 'lucide-react'
import PaymentModal from '@/components/ui/PaymentModal'

interface PlanCardProps {
  name: string
  price: number
  badge: string | null
  highlighted: boolean
  features: string[]
  dian: boolean
  type: 'facturacion' | 'integral'
}

function formatCOP(amount: number): string {
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(amount)
}

export default function PlanCard({ name, price, badge, highlighted, features, dian, type }: PlanCardProps) {
  const [modalOpen, setModalOpen] = useState(false)

  return (
    <>
      <div
        className={`relative flex flex-col bg-white rounded-2xl p-6 transition-all duration-300 hover:-translate-y-1 ${
          highlighted ? 'shadow-2xl' : 'shadow-sm hover:shadow-lg'
        }`}
        style={{
          border: highlighted ? '2px solid var(--cyan)' : '1px solid var(--gray-border)',
        }}
      >
        {/* Badge */}
        {badge && (
          <div
            className="absolute -top-3.5 left-1/2 -translate-x-1/2 px-4 py-1 rounded-full text-xs font-bold whitespace-nowrap"
            style={{
              backgroundColor: highlighted ? 'var(--cyan)' : 'var(--navy)',
              color: highlighted ? 'var(--navy)' : 'white',
            }}
          >
            {badge}
          </div>
        )}

        {/* DIAN badge */}
        {dian && (
          <div
            className="absolute top-4 right-4 w-7 h-7 rounded-full flex items-center justify-center text-xs"
            style={{ backgroundColor: 'rgba(87, 150, 1, 0.12)', color: 'var(--green)' }}
            title="Incluye habilitación DIAN"
          >
            <Check size={14} strokeWidth={3} />
          </div>
        )}

        {/* Plan name */}
        <h3 className="text-base font-bold mb-1" style={{ color: 'var(--navy)' }}>{name}</h3>
        <p className="text-xs mb-4" style={{ color: 'var(--gray)' }}>
          {type === 'integral' ? 'Facturación + Nómina + Recepción' : 'Facturación electrónica'}
        </p>

        {/* Price */}
        <div className="mb-5">
          <span className="text-3xl font-extrabold" style={{ color: 'var(--navy)' }}>
            {formatCOP(price)}
          </span>
          <span className="text-sm font-medium ml-1" style={{ color: 'var(--gray)' }}>/año</span>
        </div>

        {/* Features */}
        <ul className="flex flex-col gap-2.5 mb-6 flex-1">
          {features.map((feature, i) => {
            const isNegative = feature.toLowerCase().includes('no incluye')
            return (
              <li key={i} className="flex items-start gap-2 text-sm">
                {isNegative ? (
                  <X size={14} className="mt-0.5 shrink-0" style={{ color: '#ef4444' }} />
                ) : (
                  <Check size={14} className="mt-0.5 shrink-0" style={{ color: 'var(--green)' }} strokeWidth={2.5} />
                )}
                <span style={{ color: isNegative ? 'var(--gray)' : '#334155' }}>{feature}</span>
              </li>
            )
          })}
        </ul>

        {/* CTA */}
        <button
          onClick={() => setModalOpen(true)}
          className="w-full flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all duration-200 hover:-translate-y-0.5 active:translate-y-0"
          style={{
            backgroundColor: highlighted ? 'var(--cyan)' : 'var(--navy)',
            color: highlighted ? 'var(--navy)' : 'white',
          }}
        >
          <ShoppingCart size={15} />
          Comprar ahora
        </button>
      </div>

      {/* Payment Modal */}
      <PaymentModal
        isOpen={modalOpen}
        onClose={() => setModalOpen(false)}
        planName={name}
        planPrice={price}
      />
    </>
  )
}

import crypto from 'crypto'

const PAYZEN_SHOP_ID = process.env.PAYZEN_SHOP_ID!
const PAYZEN_KEY = process.env.PAYZEN_PRODUCTION_KEY ?? process.env.PAYZEN_TEST_KEY!
const PAYZEN_BASE_URL = 'https://api.payzen.com/api-payment/V4'

interface CreateOrderParams {
  orderId: string
  amount: number
  customerEmail: string
  customerName: string
  planName: string
}

interface PayZenOrderResult {
  transactionId: string | null
  redirectUrl: string | null
  formToken: string | null
}

export async function createPayZenOrder(params: CreateOrderParams): Promise<PayZenOrderResult> {
  const { orderId, amount, customerEmail, customerName, planName } = params

  const payload = {
    amount: amount, // COP en centavos
    currency: 'COP',
    orderId,
    customer: {
      email: customerEmail,
      reference: customerEmail,
      billingDetails: { firstName: customerName.split(' ')[0], lastName: customerName.split(' ').slice(1).join(' ') || customerName },
    },
    metadata: { planName },
    ipnTargetUrl: `${process.env.NEXT_PUBLIC_APP_URL ?? 'https://landing.emision.co'}/api/webhooks/payzen`,
  }

  const auth = Buffer.from(`${PAYZEN_SHOP_ID}:${PAYZEN_KEY}`).toString('base64')

  const res = await fetch(`${PAYZEN_BASE_URL}/Charge/CreatePayment`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Basic ${auth}`,
    },
    body: JSON.stringify(payload),
  })

  if (!res.ok) {
    const err = await res.text()
    throw new Error(`PayZen error: ${err}`)
  }

  const data = await res.json()

  return {
    transactionId: data.answer?.transactions?.[0]?.uuid ?? null,
    redirectUrl: data.answer?.redirectSuccessUrl ?? null,
    formToken: data.answer?.formToken ?? null,
  }
}
